'use client';

import { useState, useMemo } from 'react';
import Link from 'next/link';
import { AdminMetricCard } from '@/components/admin/AdminMetricCard';
import { LiquidityPanel } from '@/components/admin/LiquidityPanel';
import { AdminTransactionRow } from '@/components/admin/AdminTransactionRow';
import { ADMIN_MOCK_TRANSACTIONS, ADMIN_MOCK_LIQUIDITY } from '@/data/mockAdminData';
import { formatCurrency } from '@/lib/formatters';
import type { TransactionStatus } from '@/types';

const STATUS_FILTERS: { value: TransactionStatus | 'ALL'; label: string }[] = [
  { value: 'ALL',            label: 'All'       },
  { value: 'COMPLETED',      label: 'Completed' },
  { value: 'USDC_SENT',      label: 'Bridging'  },
  { value: 'NAIRA_DEBITED',  label: 'Debited'   },
  { value: 'INITIATED',      label: 'Initiated' },
  { value: 'FAILED',         label: 'Failed'    },
];

export default function AdminPage() {
  const [statusFilter, setStatusFilter] = useState<TransactionStatus | 'ALL'>('ALL');
  const [search, setSearch] = useState('');

  const txs = ADMIN_MOCK_TRANSACTIONS;

  const totalVolume  = txs.filter(t => t.status === 'COMPLETED').reduce((s, t) => s + t.senderAmount, 0);
  const failedCount  = txs.filter(t => t.status === 'FAILED').length;
  const pendingCount = txs.filter(t => !['COMPLETED','FAILED'].includes(t.status)).length;
  const successRate  = txs.length > 0
    ? ((txs.filter(t => t.status === 'COMPLETED').length / txs.length) * 100).toFixed(1)
    : '0';

  const filtered = useMemo(() => {
    return txs.filter((tx) => {
      if (statusFilter !== 'ALL' && tx.status !== statusFilter) return false;
      if (search.trim()) {
        const q = search.toLowerCase();
        return (
          tx.recipientName.toLowerCase().includes(q) ||
          tx.userId.toLowerCase().includes(q) ||
          tx.id.toLowerCase().includes(q) ||
          (tx.failureReason ?? '').toLowerCase().includes(q)
        );
      }
      return true;
    });
  }, [txs, statusFilter, search]);

  return (
    <div className="min-h-screen bg-[#080812] text-zinc-100">
      {/* Top bar */}
      <header className="sticky top-0 z-30 flex h-14 items-center justify-between border-b border-[#1a1a2e] bg-[#080812]/90 px-5 backdrop-blur-sm">
        <div className="flex items-center gap-3">
          <div className="flex h-7 w-7 items-center justify-center rounded-lg bg-indigo-600">
            <svg width="14" height="14" viewBox="0 0 16 16" fill="none">
              <path d="M2 8h5M9 4l5 4-5 4" stroke="white" strokeWidth="1.6" strokeLinecap="round" strokeLinejoin="round"/>
            </svg>
          </div>
          <span className="text-sm font-semibold tracking-tight text-zinc-100">
            Remitly<span className="text-indigo-400">NG</span>
          </span>
          <span className="rounded-md border border-amber-500/30 bg-amber-500/10 px-2 py-0.5 text-[10px] font-bold uppercase tracking-widest text-amber-400">
            Admin
          </span>
        </div>
        <Link
          href="/"
          className="flex items-center gap-1.5 text-[12.5px] text-zinc-500 hover:text-zinc-300 transition-colors"
        >
          <svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
            <line x1="19" y1="12" x2="5" y2="12"/>
            <polyline points="12 19 5 12 12 5"/>
          </svg>
          User dashboard
        </Link>
      </header>

      <main className="mx-auto max-w-6xl px-4 py-8">

        {/* Page heading */}
        <div className="mb-7">
          <h1 className="text-xl font-semibold tracking-tight text-zinc-100">Admin dashboard</h1>
          <p className="mt-1 text-sm text-zinc-600">Monitor transactions, liquidity, and system health</p>
        </div>

        {/* Metrics row */}
        <div className="grid grid-cols-2 sm:grid-cols-4 gap-4 mb-7">
          <AdminMetricCard
            label="Total volume"
            value={formatCurrency(totalVolume, 'NGN')}
            sub={`${txs.filter(t => t.status === 'COMPLETED').length} completed`}
            accent="indigo"
            icon={<svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round"><polyline points="3 15 9 9 13 13 21 5"/><polyline points="17 5 21 5 21 9"/></svg>}
          />
          <AdminMetricCard
            label="Success rate"
            value={`${successRate}%`}
            sub={`${txs.length} total transfers`}
            accent="green"
            icon={<svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round"><polyline points="20 6 9 17 4 12"/></svg>}
          />
          <AdminMetricCard
            label="Pending"
            value={pendingCount.toString()}
            sub="in-flight transfers"
            accent="amber"
            icon={<svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round"><circle cx="12" cy="12" r="10"/><polyline points="12 6 12 12 16 14"/></svg>}
          />
          <AdminMetricCard
            label="Failed"
            value={failedCount.toString()}
            sub="require attention"
            accent={failedCount > 0 ? 'red' : 'default'}
            icon={<svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round"><circle cx="12" cy="12" r="10"/><line x1="12" y1="8" x2="12" y2="12"/><line x1="12" y1="16" x2="12.01" y2="16"/></svg>}
          />
        </div>

        {/* Two-column layout */}
        <div className="grid grid-cols-1 xl:grid-cols-[1fr_280px] gap-6 items-start">

          {/* Left — transaction monitor */}
          <div className="flex flex-col gap-5">
            <div className="flex items-center justify-between">
              <h2 className="text-sm font-semibold text-zinc-200">Transaction monitor</h2>
              <span className="text-[11px] text-zinc-600">{filtered.length} shown</span>
            </div>

            {/* Search + filter */}
            <div className="flex flex-col sm:flex-row gap-3">
              <div className="relative flex-1">
                <svg className="absolute left-3.5 top-1/2 -translate-y-1/2 text-zinc-600" width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                  <circle cx="11" cy="11" r="8"/><line x1="21" y1="21" x2="16.65" y2="16.65"/>
                </svg>
                <input
                  type="text"
                  placeholder="Search by recipient, user ID, tx ID..."
                  value={search}
                  onChange={(e) => setSearch(e.target.value)}
                  className="w-full rounded-xl border border-[#1e1e32] bg-[#0f0f1a] pl-9 pr-4 py-2.5 text-sm text-zinc-100 placeholder:text-zinc-700 outline-none focus:border-indigo-500/50 focus:ring-1 focus:ring-indigo-500/20 transition-all"
                />
              </div>
              <div className="flex gap-1.5 flex-wrap">
                {STATUS_FILTERS.map((f) => (
                  <button
                    key={f.value}
                    type="button"
                    onClick={() => setStatusFilter(f.value)}
                    className={[
                      'rounded-lg border px-3 py-2 text-[11.5px] font-medium transition-all duration-150',
                      statusFilter === f.value
                        ? 'border-indigo-500/40 bg-indigo-600/20 text-indigo-400'
                        : 'border-[#1e1e32] bg-[#0f0f1a] text-zinc-600 hover:text-zinc-400 hover:border-[#2a2a45]',
                    ].join(' ')}
                  >
                    {f.label}
                  </button>
                ))}
              </div>
            </div>

            {/* Transaction rows */}
            {filtered.length > 0 ? (
              <div className="flex flex-col gap-2.5">
                {filtered.map((tx) => (
                  <AdminTransactionRow key={tx.id} transaction={tx} />
                ))}
              </div>
            ) : (
              <div className="flex flex-col items-center justify-center gap-3 rounded-2xl border border-[#1e1e32] bg-[#0f0f1a] py-12">
                <p className="text-sm font-medium text-zinc-600">No transactions match</p>
                <button type="button" onClick={() => { setStatusFilter('ALL'); setSearch(''); }} className="text-[12px] text-indigo-400 hover:text-indigo-300 transition-colors">
                  Clear filters
                </button>
              </div>
            )}
          </div>

          {/* Right — liquidity + system */}
          <div className="flex flex-col gap-4">
            <LiquidityPanel data={ADMIN_MOCK_LIQUIDITY} />

            {/* Failed alerts */}
            {failedCount > 0 && (
              <div className="rounded-xl border border-red-500/20 bg-red-500/5 p-4">
                <div className="flex items-center gap-2 mb-3">
                  <svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="#f87171" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                    <path d="M10.29 3.86L1.82 18a2 2 0 0 0 1.71 3h16.94a2 2 0 0 0 1.71-3L13.71 3.86a2 2 0 0 0-3.42 0z"/>
                    <line x1="12" y1="9" x2="12" y2="13"/>
                    <line x1="12" y1="17" x2="12.01" y2="17"/>
                  </svg>
                  <p className="text-[12px] font-semibold text-red-400">{failedCount} failed transfer{failedCount > 1 ? 's' : ''}</p>
                </div>
                {txs.filter(t => t.status === 'FAILED').map((tx) => (
                  <div key={tx.id} className="mb-2 last:mb-0">
                    <p className="text-[11.5px] text-zinc-400 font-medium">{tx.recipientName}</p>
                    <p className="text-[10.5px] text-red-400/70">{tx.failureReason}</p>
                  </div>
                ))}
              </div>
            )}

            {/* System info */}
            <div className="rounded-xl border border-[#1e1e32] bg-[#0f0f1a] p-4">
              <p className="text-[10px] font-semibold uppercase tracking-widest text-zinc-700 mb-3">System</p>
              {[
                { label: 'Network',    value: 'Base Sepolia', ok: true  },
                { label: 'Bridge',     value: 'Operational',  ok: true  },
                { label: 'Paystack',   value: 'Operational',  ok: true  },
                { label: 'Firestore',  value: 'Operational',  ok: true  },
              ].map((row) => (
                <div key={row.label} className="flex items-center justify-between py-2 border-b border-[#131325] last:border-0">
                  <p className="text-[12px] text-zinc-600">{row.label}</p>
                  <span className={`flex items-center gap-1.5 text-[11px] font-medium ${row.ok ? 'text-emerald-400' : 'text-red-400'}`}>
                    <span className={`h-1.5 w-1.5 rounded-full ${row.ok ? 'bg-emerald-400' : 'bg-red-400'}`} />
                    {row.value}
                  </span>
                </div>
              ))}
            </div>
          </div>
        </div>
      </main>
    </div>
  );
}
